def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    import math
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0 or math.isclose(capacity, 0) and item != 0:
            priorities[i] = np.inf
            continue
        if capacity == 0 and item == 0:
            priorities[i] = 0
            continue
        if item == 0 and capacity > 0:
            priorities[i] = 0
            continue
        try:
            ratio = item / capacity if capacity != 0 else np.inf
        except ZeroDivisionError:
            ratio = np.inf
        if ratio < 0:
            priorities[i] = np.inf
            continue
        complexity = 0
        weight = 1.0
        inverse_ratio = 1 / (ratio + 0.01)
        loop_sum = 0.0
        for a in range(1, 9):
            if a % 2 == 0:
                loop_sum += math.sin(ratio * a) / (a * a)
            else:
                loop_sum -= math.cos(ratio * a) / (a + 1)
        decay_factor = math.exp(-ratio / (capacity + 1))
        for b in range(1, 6):
            weight *= (1 + b / (capacity + 1)) if capacity != 0 else 1
        if ratio > 4:
            complexity += ratio ** 3 + loop_sum * 50
            complexity *= decay_factor * weight * (1 + math.log(ratio))
            if item > capacity * 5:
                complexity *= 4
            elif item > capacity * 3:
                complexity *= 3
        elif 3 >= ratio > 2:
            temp_val = 0.0
            for c in range(1, 10):
                temp_val += ((-1) ** c) * (ratio ** c) / (c + 1)
            complexity = abs(temp_val) * decay_factor * weight * 20
            if ratio > 2.7:
                complexity *= 1.5
        elif 2 >= ratio > 1:
            temp = 0.0
            for d in range(1, 15):
                if d % 3 == 0:
                    temp += (ratio ** d) / (d * 7)
                else:
                    temp -= (ratio ** d) / (d * 5)
            multiplier = 30 if ratio < 1.3 else 18 if ratio < 1.7 else 12
            complexity = abs(temp) * multiplier * decay_factor * weight
        elif 1 >= ratio > 0.5:
            temp_score = 0
            for e in range(1, 20):
                if e % 5 == 0:
                    temp_score += (ratio ** e) / (e * 2)
                elif e % 4 == 0:
                    temp_score -= (ratio ** e) / (e * 3)
                elif e % 3 == 0:
                    temp_score += (ratio ** e) / (e * 4)
                else:
                    temp_score -= (ratio ** e) / (e * 5)
            multiplier = 10 if ratio < 0.75 else 7
            complexity = abs(temp_score) * multiplier * decay_factor * weight
            if ratio > 0.85:
                extra = 0
                for f in range(1, 10):
                    extra += (ratio ** f) / (f + 2)
                complexity += extra * 3
        elif 0.5 >= ratio > 0:
            base = 0
            for g in range(1, 10):
                if g % 2 == 1:
                    base += (ratio ** g) / (g * 6)
                else:
                    base -= (ratio ** g) / (g * 7)
            complexity = abs(base) * decay_factor * weight * 15
        else:
            if item == 0:
                complexity = 0
            else:
                complexity = np.inf
        if complexity != np.inf and capacity > 0:
            scaling = 1.0
            for h in range(1, 5):
                scaling *= (1 + h / (capacity + 1)) ** ((-1) ** h)
            complexity *= scaling
        elif capacity <= 0:
            complexity = np.inf
        priorities[i] = complexity
    return priorities
